import 'package:flutter/material.dart';

class ProductionLogger {
  static void log(String message) {
    debugPrint(message);
  }

  static void logRequest(String url, String method, Map<String, dynamic> body) {
    log('HTTP Request - URL: $url, Method: $method, Body: $body');
  }

  static void logResponse(int statusCode, Map<String, dynamic> response) {
    log('HTTP Response - Status Code: $statusCode, Response: $response');
  }

  static void logDatabaseOperation(String operation, String details) {
    log('Database Operation - Operation: $operation, Details: $details');
  }

  static void logAuthenticationFlow(String step, Map<String, dynamic> data) {
    log('Authentication Flow - Step: $step, Data: $data');
  }

  static void logUserInteraction(String action, String details) {
